import sys
import json
from typing import List

class Solution:
    def countTeamSplits(self, scores: List[int]) -> int:
        n = len(scores)
        total_sum = sum(scores)
        count = 0
        current_left_sum = 0
        for j in range(n - 1):
            current_left_sum += scores[j]
            current_right_sum = total_sum - current_left_sum
            diff = current_left_sum - current_right_sum
            if diff % 2 == 0:
                count += 1
        return count

def main():
    input_data = sys.stdin.read().strip()
    if not input_data:
        return

    try:
        if "scores =" in input_data:
            data_str = input_data.split("scores =")[-1].strip()
            scores = json.loads(data_str)
        else:
            scores = json.loads(input_data)
    except:
        import re
        match = re.search(r'\[.*\]', input_data)
        if match:
            scores = json.loads(match.group())
        else:
            return

    sol = Solution()
    print(sol.countTeamSplits(scores))

if __name__ == "__main__":
    main()

