class Solution:
    def findUniqueSignal(self, signals: List[int], w: int) -> int:
        n = len(signals)
        num_windows = n - w + 1
        window_presence = {}

        for i in range(num_windows):
            window = signals[i : i + w]
            unique_in_window = set(window)
            for val in unique_in_window:
                if val not in window_presence:
                    window_presence[val] = 0
                window_presence[val] += 1

        candidates = [val for val, count in window_presence.items() if count == 1]

        if not candidates:
            return -1
        return max(candidates)

def main():
    input_data = sys.stdin.read().strip()
    if not input_data:
        return

    try:
        lines = input_data.splitlines()
        signals_line = ""
        w_line = ""

        for line in lines:
            if "signals =" in line:
                signals_line = line.split("signals =")[1].split(", w =")[0].strip()
                w_line = line.split("w =")[1].strip()

        if not signals_line:
            data = json.loads(input_data.replace("signals =", '"signals":').replace("w =", '"w":').replace("'", '"'))
            signals = data["signals"]
            w = data["w"]
        else:
            signals = json.loads(signals_line)
            w = int(w_line)

        sol = Solution()
        print(sol.findUniqueSignal(signals, w))
    except:
        import re
        nums = re.findall(r'\[.*?\]', input_data)
        signals = json.loads(nums[0])
        w_match = re.search(r'w\s*=\s*(\d+)', input_data)
        w = int(w_match.group(1))
        sol = Solution()
        print(sol.findUniqueSignal(signals, w))

