class Solution:
    def aggregatePeakScores(self, scoreList: List[int], d: int) -> int:
        total = 0
        n = len(scoreList)
        for i in range(n):
            left_valid = (i - d) >= 0
            right_valid = (i + d) < n
            if left_valid and right_valid:
                if scoreList[i] > scoreList[i - d] and scoreList[i] > scoreList[i + d]:
                    total += scoreList[i]
            elif left_valid:
                if scoreList[i] > scoreList[i - d]:
                    total += scoreList[i]
            elif right_valid:
                if scoreList[i] > scoreList[i + d]:
                    total += scoreList[i]
            else:
                total += scoreList[i]
        return total

def main():
    input_data = sys.stdin.read()
    if not input_data:
        return
    try:
        data = json.loads(input_data)
        scoreList = data.get("scoreList")
        d = data.get("d")
        if scoreList is not None and d is not None:
            sol = Solution()
            print(sol.aggregatePeakScores(scoreList, d))
    except:
        lines = input_data.strip().splitlines()
        if len(lines) >= 2:
            scoreList = json.loads(lines[0])
            d = int(lines[1])
            sol = Solution()
            print(sol.aggregatePeakScores(scoreList, d))

