import sys

class Solution:
    def computeMaxDisparity(self, seq: str) -> int:
        counts = {}
        for char in seq:
            counts[char] = counts.get(char, 0) + 1

        odd_counts = []
        even_counts = []

        for char in counts:
            freq = counts[char]
            if freq % 2 == 0:
                even_counts.append(freq)
            else:
                odd_counts.append(freq)

        max_disparity = -float('inf')
        for o in odd_counts:
            for e in even_counts:
                max_disparity = max(max_disparity, o - e)

        return int(max_disparity)

def main():
    input_data = sys.stdin.read().strip()
    if not input_data:
        return

    if input_data.startswith("seq = "):
        seq = input_data[len("seq = "):].strip('"')
    else:
        seq = input_data.strip('"')

    solution = Solution()
    result = solution.computeMaxDisparity(seq)
    print(result)

