    main()

import sys

class Solution:
    def countReplicas(self, recordedReadings, ranges) -> int:
        n = len(recordedReadings)
        if n == 0:
            return 0

        diffs = [0] * n
        for i in range(1, n):
            diffs[i] = diffs[i-1] + (recordedReadings[i] - recordedReadings[i-1])

        lower_bound = -float('inf')
        upper_bound = float('inf')

        for i in range(n):
            l_i, r_i = ranges[i]
            d_i = diffs[i]

            current_min_x = l_i - d_i
            current_max_x = r_i - d_i

            lower_bound = max(lower_bound, current_min_x)
            upper_bound = min(upper_bound, current_max_x)

        if lower_bound > upper_bound:
            return 0
        else:
            return int(upper_bound - lower_bound + 1)

def main():
    import json
    input_data = sys.stdin.read().splitlines()
    if not input_data:
        return

    try:
        recordedReadings = json.loads(input_data[0])
        ranges = json.loads(input_data[1])
    except:
        raw = "".join(input_data)
        if "recordedReadings =" in raw:
            parts = raw.split("ranges =")
            rr_part = parts[0].split("=")[1].strip().rstrip(",")
            ranges_part = parts[1].strip()
            recordedReadings = json.loads(rr_part)
            ranges = json.loads(ranges_part)
        else:
            return

    sol = Solution()
    print(sol.countReplicas(recordedReadings, ranges))

if __name__ == "__main__":
    main()

import sys

class Solution:
    def longestSymmetricMelody(self, S: str, T: str) -> int:
        max_len = 0
        n = len(S)
        m = len(T)

        s_segments = [""]
        for i in range(n):
            for j in range(i + 1, n + 1):
                s_segments.append(S[i:j])

        t_segments = [""]
        for i in range(m):
            for j in range(i + 1, m + 1):
                t_segments.append(T[i:j])

        for s_seg in s_segments:
            for t_seg in t_segments:
                combined = s_seg + t_seg
                if not combined:
                    continue
                if combined == combined[::-1]:
                    if len(combined) > max_len:
                        max_len = len(combined)
        return max_len

def main():
    input_data = sys.stdin.read().splitlines()
    if len(input_data) < 2:
        return
    s_val = input_data[0].strip()
    t_val = input_data[1].strip()

    sol = Solution()
    print(sol.longestSymmetricMelody(s_val, t_val))

if __name__ == "__main__":
    main()

