class Solution:
    def countClusters(self, blueprints: List[List[int]], threshold: int) -> int:
        n = len(blueprints)
        if n == 0:
            return 0

        sets = [set(b) for b in blueprints]
        parent = list(range(n))

        def find(i):
            if parent[i] == i:
                return i
            parent[i] = find(parent[i])
            return parent[i]

        def union(i, j):
            root_i = find(i)
            root_j = find(j)
            if root_i != root_j:
                parent[root_i] = root_j
                return True
            return False

        for i in range(n):
            for j in range(i + 1, n):
                common = len(sets[i].intersection(sets[j]))
                if common >= threshold:
                    union(i, j)

        clusters = 0
        for i in range(n):
            if parent[i] == i:
                clusters += 1
        return clusters

def main():
    input_data = sys.stdin.read()
    if not input_data.strip():
        return

    try:
        data = json.loads(input_data)
        if isinstance(data, dict):
            blueprints = data.get("blueprints")
            threshold = data.get("threshold")
        else:
            lines = input_data.strip().splitlines()
            blueprints = json.loads(lines[0].split("=")[1].strip() if "=" in lines[0] else lines[0])
            threshold = json.loads(lines[1].split("=")[1].strip() if "=" in lines[1] else lines[1])

        sol = Solution()
        print(sol.countClusters(blueprints, threshold))
    except:
        raw = input_data.replace("blueprints =", "").replace("threshold =", "").splitlines()
        parts = []
        for r in raw:
            if r.strip():
                parts.append(r.strip().rstrip(','))
        if len(parts) >= 2:
            blueprints = json.loads(parts[0])
            threshold = int(parts[1])
            sol = Solution()
            print(sol.countClusters(blueprints, threshold))

