def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    n = int(input_data[0])
    idx = 1

    wheels_data = []
    for _ in range(n):
        m = int(input_data[idx])
        idx += 1
        counts = {}
        for _ in range(m):
            symbol = int(input_data[idx])
            idx += 1
            counts[symbol] = counts.get(symbol, 0) + 1
        wheels_data.append((m, counts))

    max_prob = 0.0

    for i in range(n):
        m_i, counts_i = wheels_data[i]
        for j in range(i + 1, n):
            m_j, counts_j = wheels_data[j]

            common_sum = 0
            if len(counts_i) < len(counts_j):
                for symbol, count in counts_i.items():
                    if symbol in counts_j:
                        common_sum += count * counts_j[symbol]
            else:
                for symbol, count in counts_j.items():
                    if symbol in counts_i:
                        common_sum += count * counts_i[symbol]

            prob = common_sum / (m_i * m_j)
            if prob > max_prob:
                max_prob = prob

    print(f"{max_prob:.15f}")

def main():
    solve()

