import sys

def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    n = int(input_data[0])
    m = int(input_data[1])
    x = list(map(int, input_data[2:n+2]))
    y = list(map(int, input_data[n+2:]))

    left = [-1] * m
    curr = 0
    for i in range(n):
        if curr < m and x[i] == y[curr]:
            left[curr] = i
            curr += 1

    if curr < m:
        print("No")
        return

    right = [-1] * m
    curr = m - 1
    for i in range(n - 1, -1, -1):
        if curr >= 0 and x[i] == y[curr]:
            right[curr] = i
            curr -= 1

    possible = False
    for i in range(m):
        if left[i] < right[i]:
            possible = True
            break

    if possible:
        print("Yes")
    else:
        print("No")

