public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int[] arr = new int[5];
        for (int i = 0; i < 5; i++) {
            arr[i] = sc.nextInt();
        }
        sc.close();

        if (isSorted(arr)) {
            System.out.println("No");
            return;
        }

        for (int i = 0; i < 4; i++) {
            swap(arr, i, i + 1);
            if (isSorted(arr)) {
                System.out.println("Yes");
                return;
            }
            swap(arr, i, i + 1);
        }

        System.out.println("No");
    }

    static boolean isSorted(int[] arr) {
        for (int i = 0; i < 5; i++) {
            if (arr[i] != i + 1) {
                return false;
            }
        }
        return true;
    }

    static void swap(int[] arr, int i, int j) {
        int temp = arr[i];
        arr[i] = arr[j];
        arr[j] = temp;
    }
}

