import (
    "fmt"
    "math"
)

func majority(a, b, c int) int {
    if a+b+c >= 2 {
        return 1
    }
    return 0
}

func minCostToFlip(d string, n int) int {
    length := 1
    for i := 0; i < n; i++ {
        length *= 3
    }

    dp := make([][][2]int, n+1)
    for i := 0; i <= n; i++ {
        levelLen := 1
        for j := 0; j < n-i; j++ {
            levelLen *= 3
        }
        dp[i] = make([][2]int, levelLen)
    }

    for i := 0; i < length; i++ {
        if d[i] == '0' {
            dp[0][i][0] = 0
            dp[0][i][1] = 1
        } else {
            dp[0][i][0] = 1
            dp[0][i][1] = 0
        }
    }

    for level := 1; level <= n; level++ {
        prevLen := 1
        for j := 0; j < n-level+1; j++ {
            prevLen *= 3
        }
        currLen := prevLen / 3

        for i := 0; i < currLen; i++ {
            idx := i * 3

            dp[level][i][0] = math.MaxInt32
            dp[level][i][1] = math.MaxInt32

            for v0 := 0; v0 <= 1; v0++ {
                for v1 := 0; v1 <= 1; v1++ {
                    for v2 := 0; v2 <= 1; v2++ {
                        result := majority(v0, v1, v2)
                        cost := dp[level-1][idx][v0] + dp[level-1][idx+1][v1] + dp[level-1][idx+2][v2]

                        if dp[level][i][result] > cost {
                            dp[level][i][result] = cost
                        }
                    }
                }
            }
        }
    }

    original := dp[n][0][0]
    flipped := dp[n][0][1]

    if original <= flipped {
        return flipped
    } else {
        return original
    }
}

func main() {
    var n int
    var d string
    fmt.Scan(&n)
    fmt.Scan(&d)

    result := minCostToFlip(d, n)
    fmt.Println(result)
}

package main

import (
	"bufio"
	"container/heap"
	"fmt"
	"os"
	"sort"
)

type State struct {
	i, j, k int
	score   int64
}

type MaxHeap []State

func (h MaxHeap) Len() int           { return len(h) }
func (h MaxHeap) Less(i, j int) bool { return h[i].score > h[j].score }
func (h MaxHeap) Swap(i, j int)      { h[i], h[j] = h[j], h[i] }

func (h *MaxHeap) Push(x interface{}) {
	*h = append(*h, x.(State))
}

func (h *MaxHeap) Pop() interface{} {
	old := *h
	n := len(old)
	x := old[n-1]
	*h = old[0 : n-1]
	return x
}

func main() {
	reader := bufio.NewReader(os.Stdin)
	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n, k int
	fmt.Fscan(reader, &n, &k)

	x := make([]int64, n)
	y := make([]int64, n)
	z := make([]int64, n)

	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &x[i])
	}
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &y[i])
	}
	for i := 0; i < n; i++ {
		fmt.Fscan(reader, &z[i])
	}

	sort.Slice(x, func(i, j int) bool { return x[i] > x[j] })
	sort.Slice(y, func(i, j int) bool { return y[i] > y[j] })
	sort.Slice(z, func(i, j int) bool { return z[i] > z[j] })

	calcScore := func(i, j, k int) int64 {
		return x[i]*y[j] + y[j]*z[k] + z[k]*x[i]
	}

	h := &MaxHeap{}
	heap.Init(h)

	visited := make(map[[3]int]bool)

	initialScore := calcScore(0, 0, 0)
	heap.Push(h, State{0, 0, 0, initialScore})
	visited[[3]int{0, 0, 0}] = true

	var result int64

	for count := 0; count < k; count++ {
		current := heap.Pop(h).(State)
		result = current.score

		nextStates := [][3]int{
			{current.i + 1, current.j, current.k},
			{current.i, current.j + 1, current.k},
			{current.i, current.j, current.k + 1},
		}

		for _, next := range nextStates {
			if next[0] < n && next[1] < n && next[2] < n {
				key := [3]int{next[0], next[1], next[2]}
				if !visited[key] {
					visited[key] = true
					score := calcScore(next[0], next[1], next[2])
					heap.Push(h, State{next[0], next[1], next[2], score})
				}
			}
		}
	}

	fmt.Fprintln(writer, result)
}

