func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Split(bufio.ScanWords)

	scanner.Scan()
	n, _ := strconv.Atoi(scanner.Text())

	wheels := make([]map[int]int, n)
	sizes := make([]int, n)

	for i := 0; i < n; i++ {
		scanner.Scan()
		m, _ := strconv.Atoi(scanner.Text())
		sizes[i] = m
		wheels[i] = make(map[int]int)

		for j := 0; j < m; j++ {
			scanner.Scan()
			symbol, _ := strconv.Atoi(scanner.Text())
			wheels[i][symbol]++
		}
	}

	maxProb := 0.0

	for i := 0; i < n; i++ {
		for j := i + 1; j < n; j++ {
			prob := calculateProbability(wheels[i], wheels[j], sizes[i], sizes[j])
			if prob > maxProb {
				maxProb = prob
			}
		}
	}

	fmt.Printf("%.15f\n", maxProb)
}

func calculateProbability(wheel1, wheel2 map[int]int, size1, size2 int) float64 {
	prob := 0.0

	for symbol, count1 := range wheel1 {
		if count2, exists := wheel2[symbol]; exists {
			prob += float64(count1) / float64(size1) * float64(count2) / float64(size2)
		}
	}

	return prob
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int N = sc.nextInt();

        List<Map<Integer, Integer>> wheels = new ArrayList<>();
        List<Integer> sizes = new ArrayList<>();

        for (int i = 0; i < N; i++) {
            int M = sc.nextInt();
            sizes.add(M);
            Map<Integer, Integer> symbolCount = new HashMap<>();
            for (int j = 0; j < M; j++) {
                int symbol = sc.nextInt();
                symbolCount.put(symbol, symbolCount.getOrDefault(symbol, 0) + 1);
            }
            wheels.add(symbolCount);
        }

        double maxProb = 0.0;

        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                double prob = calculateProbability(wheels.get(i), wheels.get(j), sizes.get(i), sizes.get(j));
                maxProb = Math.max(maxProb, prob);
            }
        }

        System.out.println(maxProb);
        sc.close();
    }

    private static double calculateProbability(Map<Integer, Integer> wheel1, Map<Integer, Integer> wheel2, int size1, int size2) {
        double prob = 0.0;

        for (Map.Entry<Integer, Integer> entry : wheel1.entrySet()) {
            int symbol = entry.getKey();
            int count1 = entry.getValue();

            if (wheel2.containsKey(symbol)) {
                int count2 = wheel2.get(symbol);
                prob += ((double) count1 / size1) * ((double) count2 / size2);
            }
        }

        return prob;
    }
}

