        String P = scanner.nextLine();
        scanner.close();

        Stack<Character> stack = new Stack<>();

        for (int i = 0; i < P.length(); i++) {
            char c = P.charAt(i);

            if (c == '(' || c == '[' || c == '<') {
                stack.push(c);
            } else {
                if (stack.isEmpty()) {
                    System.out.println("No");
                    return;
                }

                char top = stack.peek();

                if ((c == ')' && top == '(') || 
                    (c == ']' && top == '[') || 
                    (c == '>' && top == '<')) {
                    stack.pop();
                } else {
                    System.out.println("No");
                    return;
                }
            }
        }

        if (stack.isEmpty()) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
    }
}

