func hasBlockWithDuplicate(r []int, length int) bool {
    count := make(map[int]int)

    for i := 0; i < length; i++ {
        count[r[i]]++
        if count[r[i]] > 1 {
            return true
        }
    }

    for i := length; i < len(r); i++ {
        count[r[i-length]]--
        if count[r[i-length]] == 0 {
            delete(count, r[i-length])
        }

        count[r[i]]++
        if count[r[i]] > 1 {
            return true
        }
    }

    return false
}

