int main() {
    int N, M;
    long long X;
    cin >> N >> M >> X;

    vector<pair<int, int>> edges(M);
    vector<vector<int>> graph(N + 1);
    vector<vector<int>> reverse_graph(N + 1);

    for (int i = 0; i < M; i++) {
        int a, b;
        cin >> a >> b;
        edges[i] = {a, b};
        graph[a].push_back(b);
        reverse_graph[b].push_back(a);
    }

    vector<vector<long long>> dist(N + 1, vector<long long>(2, LLONG_MAX));
    priority_queue<tuple<long long, int, int>, vector<tuple<long long, int, int>>, greater<tuple<long long, int, int>>> pq;

    dist[1][0] = 0;
    pq.push({0, 1, 0});

    while (!pq.empty()) {
        auto [d, node, inverted] = pq.top();
        pq.pop();

        if (d > dist[node][inverted]) continue;

        vector<vector<int>>& current_graph = (inverted == 0) ? graph : reverse_graph;

        for (int next : current_graph[node]) {
            long long new_dist = d + 1;
            if (new_dist < dist[next][inverted]) {
                dist[next][inverted] = new_dist;
                pq.push({new_dist, next, inverted});
            }
        }

        long long invert_dist = d + X;
        int new_inverted = 1 - inverted;
        if (invert_dist < dist[node][new_inverted]) {
            dist[node][new_inverted] = invert_dist;
            pq.push({invert_dist, node, new_inverted});
        }
    }

    long long answer = min(dist[N][0], dist[N][1]);
    cout << answer << endl;

    return 0;
}

