import (
    "bufio"
    "container/heap"
    "fmt"
    "os"
)

type Edge struct {
    to int
}

type State struct {
    node     int
    inverted int
    cost     int64
}

type PQ []State

func (pq PQ) Len() int           { return len(pq) }
func (pq PQ) Less(i, j int) bool { return pq[i].cost < pq[j].cost }
func (pq PQ) Swap(i, j int)      { pq[i], pq[j] = pq[j], pq[i] }

func (pq *PQ) Push(x interface{}) {
    *pq = append(*pq, x.(State))
}

func (pq *PQ) Pop() interface{} {
    old := *pq
    n := len(old)
    item := old[n-1]
    *pq = old[0 : n-1]
    return item
}

func main() {
    scanner := bufio.NewScanner(os.Stdin)
    scanner.Split(bufio.ScanWords)

    nextInt := func() int {
        scanner.Scan()
        var n int
        fmt.Sscanf(scanner.Text(), "%d", &n)
        return n
    }

    N := nextInt()
    M := nextInt()
    X := nextInt()

    graph := make([][]int, N+1)
    reverseGraph := make([][]int, N+1)

    for i := 0; i < M; i++ {
        a := nextInt()
        b := nextInt()
        graph[a] = append(graph[a], b)
        reverseGraph[b] = append(reverseGraph[b], a)
    }

    dist := make([][]int64, N+1)
    for i := range dist {
        dist[i] = make([]int64, 2)
        dist[i][0] = 1e18
        dist[i][1] = 1e18
    }

    pq := &PQ{}
    heap.Init(pq)
    heap.Push(pq, State{1, 0, 0})
    dist[1][0] = 0

    for pq.Len() > 0 {
        current := heap.Pop(pq).(State)

        if current.node == N {
            fmt.Println(current.cost)
            return
        }

        if current.cost > dist[current.node][current.inverted] {
            continue
        }

        var edges []int
        if current.inverted == 0 {
            edges = graph[current.node]
        } else {
            edges = reverseGraph[current.node]
        }

        for _, next := range edges {
            newCost := current.cost + 1
            if newCost < dist[next][current.inverted] {
                dist[next][current.inverted] = newCost
                heap.Push(pq, State{next, current.inverted, newCost})
            }
        }

        newInverted := 1 - current.inverted
        newCost := current.cost + int64(X)
        if newCost < dist[current.node][newInverted] {
            dist[current.node][newInverted] = newCost
            heap.Push(pq, State{current.node, newInverted, newCost})
        }
    }
}

