			}
		}
	}

	minSum := L * M

	for colMask := 0; colMask < (1 << M); colMask++ {
		currentSum := 0

		for i := 0; i < L; i++ {
			onesCount := 0

			for j := 0; j < M; j++ {
				val := grid[i][j]
				if (colMask & (1 << j)) != 0 {
					val = 1 - val
				}
				if val == 1 {
					onesCount++
				}
			}

			zerosCount := M - onesCount
			if onesCount < zerosCount {
				currentSum += onesCount
			} else {
				currentSum += zerosCount
			}
		}

		if currentSum < minSum {
			minSum = currentSum
		}
	}

	fmt.Println(minSum)
