	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	var n int
	fmt.Fscanf(reader, "%d\n", &n)

	p := make([]int, n)
	for i := 0; i < n; i++ {
		fmt.Fscanf(reader, "%d", &p[i])
	}

	prefixUnique := make([]int, n)
	suffixUnique := make([]int, n)

	seen := make(map[int]bool)
	for i := 0; i < n; i++ {
		seen[p[i]] = true
		prefixUnique[i] = len(seen)
	}

	seen = make(map[int]bool)
	for i := n - 1; i >= 0; i-- {
		seen[p[i]] = true
		suffixUnique[i] = len(seen)
	}

	maxSum := 0

	for i := 1; i < n-1; i++ {
		for j := i; j < n-1; j++ {
			leftCount := prefixUnique[i-1]

			midSeen := make(map[int]bool)
			for k := i; k <= j; k++ {
				midSeen[p[k]] = true
			}
			midCount := len(midSeen)

			rightCount := suffixUnique[j+1]

			total := leftCount + midCount + rightCount
			if total > maxSum {
				maxSum = total
			}
		}
	}

	fmt.Fprintln(writer, maxSum)
}

