func countBits(mask int) int {
	count := 0
	for i := 0; i < 7; i++ {
		if (mask & (1 << i)) != 0 {
			count++
		}
	}
	return count
}

func isHarmonicEnsemble(b [7]int, mask int) bool {
	freq := make(map[int]int)
	for i := 0; i < 7; i++ {
		if (mask & (1 << i)) != 0 {
			freq[b[i]]++
		}
	}

	hasThree := false
	hasTwo := false
	valueThree := -1
	valueTwo := -1

	for val, count := range freq {
		if count == 3 {
			if hasThree {
				return false
			}
			hasThree = true
			valueThree = val
		} else if count == 2 {
			if hasTwo {
				return false
			}
			hasTwo = true
			valueTwo = val
		} else {
			return false
		}
	}

	return hasThree && hasTwo && valueThree != valueTwo
}

import java.util.*;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int[] B = new int[7];
        for (int i = 0; i < 7; i++) {
            B[i] = sc.nextInt();
        }

        if (canFormHarmonicEnsemble(B)) {
            System.out.println("Yes");
        } else {
            System.out.println("No");
        }
        sc.close();
    }

    static boolean canFormHarmonicEnsemble(int[] B) {
        for (int mask = 0; mask < (1 << 7); mask++) {
            if (Integer.bitCount(mask) == 5) {
                List<Integer> selected = new ArrayList<>();
                for (int i = 0; i < 7; i++) {
                    if ((mask & (1 << i)) != 0) {
                        selected.add(B[i]);
                    }
                }

                if (isHarmonicEnsemble(selected)) {
                    return true;
                }
            }
        }
        return false;
    }

    static boolean isHarmonicEnsemble(List<Integer> instruments) {
        Map<Integer, Integer> freq = new HashMap<>();
        for (int val : instruments) {
            freq.put(val, freq.getOrDefault(val, 0) + 1);
        }

        if (freq.size() != 2) {
            return false;
        }

        List<Integer> counts = new ArrayList<>(freq.values());
        Collections.sort(counts);

        return counts.get(0) == 2 && counts.get(1) == 3;
    }
}

