    long long total = 0;

    for (int l = 0; l < N; l++) {
        long long sum = 0;
        for (int r = l; r < N; r++) {
            sum = (sum + S[r]) % MOD;
            long long contrib = power(sum, K, MOD);
            total = (total + contrib) % MOD;
        }
    }

    cout << total << endl;

    return 0;
}

