func main() {
	var n, k int
	fmt.Scan(&n, &k)

	s := make([]int64, n)
	for i := 0; i < n; i++ {
		fmt.Scan(&s[i])
	}

	const MOD = 998244353

	result := int64(0)

	for l := 0; l < n; l++ {
		sum := int64(0)
		for r := l; r < n; r++ {
			sum = (sum + s[r]) % MOD
			powValue := modPow(sum, k, MOD)
			result = (result + powValue) % MOD
		}
	}

	fmt.Println(result)
}

func modPow(base int64, exp int, mod int64) int64 {
	result := int64(1)
	base = base % mod
	for exp > 0 {
		if exp%2 == 1 {
			result = (result * base) % mod
		}
		base = (base * base) % mod
		exp /= 2
	}
	return result
}

import java.util.*;

public class Main {
    static final long MOD = 998244353;

    static long modPow(long base, int exp, long mod) {
        long result = 1;
        base %= mod;
        while (exp > 0) {
            if ((exp & 1) == 1) {
                result = (result * base) % mod;
            }
            base = (base * base) % mod;
            exp >>= 1;
        }
        return result;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int k = sc.nextInt();
        long[] s = new long[n];

        for (int i = 0; i < n; i++) {
            s[i] = sc.nextLong();
        }

        long total = 0;

        for (int l = 0; l < n; l++) {
            long sum = 0;
            for (int r = l; r < n; r++) {
                sum = (sum + s[r]) % MOD;
                long powered = modPow(sum, k, MOD);
                total = (total + powered) % MOD;
            }
        }

        System.out.println(total);
        sc.close();
    }
}

