        long long max_r = (long long)sqrt((double)max_r_squared);

        while ((max_r + 1) * (max_r + 1) <= max_r_squared) {
            max_r++;
        }
        while (max_r * max_r > max_r_squared) {
            max_r--;
        }

        long long odd_count = (max_r + 1) / 2;
        count += odd_count;

