type Edge struct {
	to int
}

type PQItem struct {
	node int
	cost int64
	index int
}

type PriorityQueue []*PQItem

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	return pq[i].cost < pq[j].cost
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
	pq[i].index = i
	pq[j].index = j
}

func (pq *PriorityQueue) Push(x interface{}) {
	n := len(*pq)
	item := x.(*PQItem)
	item.index = n
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	old[n-1] = nil
	item.index = -1
	*pq = old[0 : n-1]
	return item
}

func main() {
	scanner := bufio.NewScanner(os.Stdin)
	scanner.Split(bufio.ScanWords)

	scanner.Scan()
	var N int
	fmt.Sscanf(scanner.Text(), "%d", &N)

	C := make([]int64, N+1)
	for i := 1; i <= N; i++ {
		scanner.Scan()
		fmt.Sscanf(scanner.Text(), "%d", &C[i])
	}

	S := make([]int, N+1)
	E := make([]int, N+1)
	for i := 1; i <= N; i++ {
		scanner.Scan()
		fmt.Sscanf(scanner.Text(), "%d", &S[i])
		scanner.Scan()
		fmt.Sscanf(scanner.Text(), "%d", &E[i])
	}

	adj := make([][]int, N+1)
	for i := 1; i <= N; i++ {
		adj[i] = make([]int, 0)
	}

	for i := 1; i <= N; i++ {
		for j := i+1; j <= N; j++ {
			if E[i] < S[j] || E[j] < S[i] {
				adj[i] = append(adj[i], j)
				adj[j] = append(adj[j], i)
			}
		}
	}

	scanner.Scan()
	var Q int
	fmt.Sscanf(scanner.Text(), "%d", &Q)

	writer := bufio.NewWriter(os.Stdout)
	defer writer.Flush()

	for q := 0; q < Q; q++ {
		scanner.Scan()
		var a int
		fmt.Sscanf(scanner.Text(), "%d", &a)
		scanner.Scan()
		var b int
		fmt.Sscanf(scanner.Text(), "%d", &b)

		dist := make([]int64, N+1)
		for i := 1; i <= N; i++ {
			dist[i] = -1
		}

		pq := &PriorityQueue{}
		heap.Init(pq)
		heap.Push(pq, &PQItem{node: a, cost: C[a]})
		dist[a] = C[a]

		for pq.Len() > 0 {
			item := heap.Pop(pq).(*PQItem)
			u := item.node
			d := item.cost

			if dist[u] != -1 && dist[u] < d {
				continue
			}

			if u == b {
				break
			}

			for _, v := range adj[u] {
				newDist := d + C[v]
				if dist[v] == -1 || newDist < dist[v] {
					dist[v] = newDist
					heap.Push(pq, &PQItem{node: v, cost: newDist})
				}
			}
		}

		fmt.Fprintln(writer, dist[b])
	}
}

