class Solution:
    def countTeamSplits(self, scores: List[int]) -> int:
        n = len(scores)
        total_sum = sum(scores)
        count = 0
        current_left_sum = 0
        for j in range(n - 1):
            current_left_sum += scores[j]
            current_right_sum = total_sum - current_left_sum
            diff = current_left_sum - current_right_sum
            if diff % 2 == 0:
                count += 1
        return count

