def solve():
    input_data = sys.stdin.read().split()
    if not input_data:
        return

    n = int(input_data[0])
    k = int(input_data[1])
    s = list(map(int, input_data[2:]))

    MOD = 998244353

    prefix_sums = [0] * (n + 1)
    for i in range(n):
        prefix_sums[i+1] = (prefix_sums[i] + s[i]) % MOD

    comb = [[0] * (k + 1) for _ in range(k + 1)]
    for i in range(k + 1):
        comb[i][0] = 1
        for j in range(1, i + 1):
            comb[i][j] = (comb[i-1][j-1] + comb[i-1][j]) % MOD

    sum_prefix_powers = [0] * (k + 1)
    ans = 0

    for r in range(1, n + 1):
        pr = prefix_sums[r]

        powers_pr = [1] * (k + 1)
        for j in range(1, k + 1):
            powers_pr[j] = (powers_pr[j-1] * pr) % MOD

        for j in range(k + 1):
            sum_prefix_powers[j] = (sum_prefix_powers[j] + prefix_sums[r-1]**j) % MOD

        current_sum = 0
        for j in range(k + 1):
            term = (comb[k][j] * powers_pr[k-j]) % MOD
            term = (term * sum_prefix_powers[j]) % MOD
            if j % 2 == 1:
                current_sum = (current_sum - term) % MOD
            else:
                current_sum = (current_sum + term) % MOD

        ans = (ans + current_sum) % MOD

    print(ans % MOD)

